from flask import Flask, jsonify, request
from pymemcache.client.base import Client as MemcacheClient
import hashlib
import json
import os
import time

app = Flask(__name__)

MEMCACHED_HOST = os.getenv("MEMCACHED_HOST", "localhost")
MEMCACHED_PORT = int(os.getenv("MEMCACHED_PORT", "11211"))
DEFAULT_TTL = int(os.getenv("CACHE_TTL_SECONDS", "60"))
API_TTL = int(os.getenv("API_CACHE_TTL_SECONDS", "30"))
DB_TTL = int(os.getenv("DB_CACHE_TTL_SECONDS", "120"))

memcache = MemcacheClient((MEMCACHED_HOST, MEMCACHED_PORT), connect_timeout=1, timeout=1)


def make_cache_key(prefix, value):
    raw = f"{prefix}:{value}"
    return hashlib.sha256(raw.encode("utf-8")).hexdigest()


def cache_get(key):
    try:
        value = memcache.get(key)
        if value is None:
            return None
        if isinstance(value, bytes):
            value = value.decode("utf-8")
        payload = json.loads(value)
        expires_at = payload.get("expires_at", 0)
        if expires_at and expires_at < time.time():
            memcache.delete(key)
            return None
        return payload.get("data")
    except Exception:
        return None


def cache_set(key, data, ttl):
    try:
        payload = {
            "expires_at": time.time() + ttl,
            "data": data,
        }
        memcache.set(key, json.dumps(payload).encode("utf-8"), expire=ttl)
    except Exception:
        pass


def fake_db_query(user_id):
    time.sleep(0.05)
    return {
        "user_id": user_id,
        "name": f"User {user_id}",
        "role": "member",
        "active": True,
        "fetched_at": time.time(),
    }


@app.route("/api/user/<user_id>")
def get_user(user_id):
    cache_key = make_cache_key("api:user", user_id)
    cached = cache_get(cache_key)
    if cached is not None:
        return jsonify({"source": "cache", "data": cached})

    data = fake_db_query(user_id)
    cache_set(cache_key, data, API_TTL)
    return jsonify({"source": "origin", "data": data})


@app.route("/api/db/user/<user_id>")
def get_user_from_db_cache(user_id):
    cache_key = make_cache_key("db:user", user_id)
    cached = cache_get(cache_key)
    if cached is not None:
        return jsonify({"source": "cache", "data": cached})

    data = fake_db_query(user_id)
    cache_set(cache_key, data, DB_TTL)
    return jsonify({"source": "origin", "data": data})


@app.route("/api/search")
def search():
    q = request.args.get("q", "").strip()
    page = request.args.get("page", "1").strip()
    cache_key = make_cache_key("api:search", f"{q}:{page}")
    cached = cache_get(cache_key)
    if cached is not None:
        return jsonify({"source": "cache", "data": cached})

    time.sleep(0.1)
    result = {
        "query": q,
        "page": page,
        "items": [
            {"id": 1, "title": f"{q} result 1"},
            {"id": 2, "title": f"{q} result 2"},
            {"id": 3, "title": f"{q} result 3"},
        ],
        "fetched_at": time.time(),
    }
    cache_set(cache_key, result, API_TTL)
    return jsonify({"source": "origin", "data": result})


@app.route("/health")
def health():
    status = {"app": "ok", "memcached": "ok"}
    try:
        memcache.set("healthcheck", b"1", expire=5)
        if memcache.get("healthcheck") is None:
            status["memcached"] = "degraded"
    except Exception:
        status["memcached"] = "down"
    return jsonify(status)


